mapper.select:
select * from ( select u.*, string_agg(r.role_name, ', ' order by r.create_time) AS role_names from sys_user u left join sys_user_role_relation rel on u.user_id = rel.user_id left join sys_role r on r.role_id = rel.role_id
and (u.username like concat('%', #{dto.keyword}, '%') or u.nickname like concat('%', #{dto.keyword}, '%')
or u.user_id = CAST(#{dto.keyword} AS BIGINT)
)
and u.create_time >= #{dto.startTime}
and u.create_time <= #{dto.endTime}
group by u.user_id ) t order by create_time desc
